module adder_32bit
(
    input [32:1] A,
    input [32:1] B,
    output [32:1] S,
    output C32
);

    wire [31:0] P, G;
    wire [32:0] C;

    assign P = A ^ B;
    assign G = A & B;
    assign C[0] = 1'b0;

    genvar i;
    generate
        for (i = 0; i < 32; i = i + 1) begin
            if (i == 0) begin
                assign C[i+1] = G[i] | (P[i] & C[i]);
            end else begin
                assign C[i+1] = G[i] | (P[i] & C[i]);
            end
        end
    endgenerate

    assign S = P ^ C[32:1];
    assign C32 = C[32];

endmodule
